package wirepb_test

import (
	"os"
	"regexp"
	"strconv"
	"strings"
	"testing"

	"github.com/google/go-cmp/cmp"
	"github.com/stretchr/testify/require"

	"github.com/grafana/dskit/httpgrpc"

	"github.com/grafana/loki/v3/pkg/engine/internal/proto/wirepb"
)

// This file guards wirepb.proto's local Header message, a hand-maintained shadow of
// dskit's httpgrpc.proto Header carried because wiresmith cannot reference message types
// generated by another protobuf runtime, and customtype is rejected on oneof variants --
// so TaskAssignMessage.metadata (a oneof-reachable field, see MessageFrame.kind) can't
// embed httpgrpc.Header directly or bridge it via customtype on a foreign type (see
// wirepb.proto's package comment and header_adapter.go). This shadow has no
// compiler-enforced link back to the vendored source, so nothing else catches
// httpgrpc.proto changing shape out from under it. Three checks guard against that:
//
//   - TestWirepbHeaderMatchesVendoredSchema normalizes and diffs wirepb.proto's Header
//     declaration against the vendored dskit Header, keyed by field number (so
//     declaration-order-only changes don't false-positive), and fails closed on anything
//     it doesn't recognize as a plain scalar/message field.
//   - TestHeaderAdapterWireFormatMatchesDskit proves HeaderAdapter's
//     Size/Marshal/UnmarshalWiresmith methods -- the ones the generated wirepb codec
//     actually calls when marshaling/unmarshaling TaskAssignMessage.Metadata -- produce
//     and consume bytes identical to httpgrpc.Header's own gogo-generated
//     Marshal/Unmarshal.
//   - TestHeaderAdapterRoundTrip regression-tests HeadersToAdapters/AdaptersToHeaders, the
//     call-site helpers pkg/engine/internal/scheduler/wire/codec.go uses.
//
// If any of these fail, the fix is:
//
//  1. Diff vendor/github.com/grafana/dskit/httpgrpc/httpgrpc.proto's Header message
//     against wirepb.proto's Header message to see what changed.
//  2. Re-sync wirepb.proto's Header field list to match.
//  3. Regenerate with the pinned wiresmith compiler (`make wiresmith-protos`, or
//     `make protos`).
//  4. Update header_adapter.go's HeaderAdapter/HeadersToAdapters/AdaptersToHeaders if the
//     field set changed (HeaderAdapter is defined as `type HeaderAdapter
//     httpgrpc.Header`, so it tracks the vendored Go struct automatically; only the
//     hand-written Equal/Compare-Wiresmith methods and the local .proto declaration need
//     attention), then re-run these tests.
//
// See also pkg/util/httpgrpcpb/drift_guard_test.go, which guards the separate, full
// HTTPRequest/HTTPResponse/Header shadow used elsewhere.

const dskitHTTPGRPCProtoPath = "../../../../../vendor/github.com/grafana/dskit/httpgrpc/httpgrpc.proto"

// protoField and protoFieldRe: see the equivalent, independently-maintained copy in
// pkg/util/httpgrpcpb/drift_guard_test.go for the full rationale. Duplicated here rather
// than shared because the two packages guard unrelated shadows and pulling in a shared
// test-only helper package for ~40 lines isn't worth the indirection.
type protoField struct {
	Type     string
	Name     string
	Repeated bool
}

var protoFieldRe = regexp.MustCompile(`^(repeated\s+)?([A-Za-z_][A-Za-z0-9_.]*)\s+([A-Za-z_][A-Za-z0-9_]*)\s*=\s*(\d+)\s*(\[[^\]]*\])?;$`)

// messageOpenRe returns a regexp matching the top-level declaration line of
// "message <name> {", anchored to the start of a line so a mention of the name inside a
// comment can't be mistaken for the real declaration.
func messageOpenRe(name string) *regexp.Regexp {
	return regexp.MustCompile(`(?m)^message\s+` + regexp.QuoteMeta(name) + `\s*\{`)
}

// extractMessageFields locates the first top-level "message <messageName> { ... }" block
// in src and parses its field declarations into a map keyed by field number, so
// declaration-order-only changes don't register as drift. wirepb.proto declares many
// other messages -- including ones with oneofs (Frame, MessageFrame) -- so this
// deliberately only descends into the one named message rather than parsing the whole
// file: this guard is only responsible for Header, not for wirepb.proto's entire grammar.
// It fails the test if the message can't be found, its braces don't balance, or any line
// in its body isn't a recognized scalar/message field declaration.
func extractMessageFields(t *testing.T, src, messageName string) map[int]protoField {
	t.Helper()

	loc := messageOpenRe(messageName).FindStringIndex(src)
	require.NotNilf(t, loc, "no top-level message %q found in proto source", messageName)
	bodyStart := loc[1]

	depth := 1
	end := -1
	for i := bodyStart; i < len(src); i++ {
		switch src[i] {
		case '{':
			depth++
		case '}':
			depth--
			if depth == 0 {
				end = i
			}
		}
		if end != -1 {
			break
		}
	}
	require.NotEqualf(t, -1, end, "unbalanced braces while scanning message %q", messageName)

	fields := map[int]protoField{}
	for i, raw := range strings.Split(src[bodyStart:end], "\n") {
		line := raw
		if idx := strings.Index(line, "//"); idx != -1 {
			line = line[:idx]
		}
		line = strings.TrimSpace(line)
		if line == "" {
			continue
		}

		m := protoFieldRe.FindStringSubmatch(line)
		require.NotNilf(t, m,
			"message %s, line %d: %q is not a recognized scalar/message field declaration. "+
				"This drift guard only understands flat fields; oneofs, maps, enums, nested "+
				"messages, and reserved statements need the guard updated -- and its author "+
				"confirming the construct's wire-compatibility story -- before it can be "+
				"trusted again", messageName, i+1, strings.TrimSpace(raw))

		num, err := strconv.Atoi(m[4])
		require.NoErrorf(t, err, "message %s: invalid field number %q", messageName, m[4])
		_, dup := fields[num]
		require.Falsef(t, dup, "message %s: duplicate field number %d", messageName, num)

		fields[num] = protoField{Type: m[2], Name: m[3], Repeated: m[1] != ""}
	}
	return fields
}

func readProtoFile(t *testing.T, path string) string {
	t.Helper()
	data, err := os.ReadFile(path)
	require.NoErrorf(t, err, "reading %s (relative paths assume `go test` runs from the package directory)", path)
	return string(data)
}

const regenInstructions = "Re-sync the field list in pkg/engine/internal/proto/wirepb/wirepb.proto's " +
	"Header message from vendor/github.com/grafana/dskit/httpgrpc/httpgrpc.proto, regenerate with " +
	"`make wiresmith-protos` (or `make protos`), and check header_adapter.go's HeaderAdapter still " +
	"bridges correctly (it delegates wire encoding to httpgrpc.Header directly, so this message's " +
	"only job is keeping the declared .proto shape honest for readers/tooling)."

// TestWirepbHeaderMatchesVendoredSchema fails if wirepb.proto's local Header message no
// longer matches dskit httpgrpc.proto's Header, modulo wiresmith field options.
func TestWirepbHeaderMatchesVendoredSchema(t *testing.T) {
	dskitSrc := readProtoFile(t, dskitHTTPGRPCProtoPath)
	wirepbSrc := readProtoFile(t, "wirepb.proto")

	want := extractMessageFields(t, dskitSrc, "Header")
	got := extractMessageFields(t, wirepbSrc, "Header")
	if diff := cmp.Diff(want, got); diff != "" {
		t.Errorf("wirepb.proto's local Header message has drifted from vendored dskit httpgrpc.proto's "+
			"Header, keyed by field number (-vendored dskit, +wirepb.proto):\n%s\n%s", diff, regenInstructions)
	}
}

// TestHeaderAdapterWireFormatMatchesDskit proves HeaderAdapter's
// Size/Marshal/UnmarshalWiresmith methods -- the wiresmith customtype contract methods
// the generated wirepb codec actually calls when marshaling/unmarshaling
// TaskAssignMessage.Metadata -- produce and consume bytes identical to httpgrpc.Header's
// own gogo-generated Marshal/Unmarshal. HeaderAdapter is defined as `type HeaderAdapter
// httpgrpc.Header` and its methods delegate directly to the gogo implementation, so this
// mostly locks in that the delegation itself stays wired up; the wirepb.Header message
// generated from wirepb.proto is never actually used as the field's Go type (customtype
// replaces it with HeaderAdapter), so it carries no independent wire-format risk of its
// own -- TestWirepbHeaderMatchesVendoredSchema above is what guards its declared shape
// staying honest as documentation.
func TestHeaderAdapterWireFormatMatchesDskit(t *testing.T) {
	original := &httpgrpc.Header{Key: "X-Scope-OrgID", Values: []string{"fake", "fake-2"}}
	adapter := wirepb.HeaderAdapter(*original)

	wantBytes, err := original.Marshal()
	require.NoError(t, err)
	require.Equal(t, len(wantBytes), adapter.SizeWiresmith())

	gotBytes := make([]byte, adapter.SizeWiresmith())
	n, err := adapter.MarshalWiresmith(gotBytes)
	require.NoError(t, err)
	require.Equal(t, len(gotBytes), n)
	require.Equalf(t, wantBytes, gotBytes,
		"HeaderAdapter.MarshalWiresmith produced different bytes than httpgrpc.Header.Marshal for an "+
			"identical value; the two should be byte-identical since MarshalWiresmith delegates to the "+
			"gogo implementation -- check header_adapter.go's delegation hasn't been changed to do its "+
			"own encoding")

	var roundTripped wirepb.HeaderAdapter
	require.NoError(t, roundTripped.UnmarshalWiresmith(gotBytes))
	require.Equal(t, adapter, roundTripped)
	require.True(t, adapter.EqualWiresmith(roundTripped))
}

// TestHeaderAdapterRoundTrip exhaustively round-trips multiple headers, each with
// multiple values, through HeadersToAdapters/AdaptersToHeaders in both directions -- the
// conversion pkg/engine/internal/scheduler/wire/codec.go uses at its call sites.
func TestHeaderAdapterRoundTrip(t *testing.T) {
	original := []*httpgrpc.Header{
		{Key: "Content-Type", Values: []string{"application/json"}},
		{Key: "X-Scope-OrgID", Values: []string{"fake", "fake-2"}},
	}

	adapters := wirepb.HeadersToAdapters(original)
	require.Len(t, adapters, len(original))
	for i, h := range original {
		require.Equal(t, h.Key, adapters[i].Key)
		require.Equal(t, h.Values, adapters[i].Values)
	}

	back := wirepb.AdaptersToHeaders(adapters)
	require.Equal(t, original, back)

	require.Nil(t, wirepb.HeadersToAdapters(nil))
	require.Nil(t, wirepb.AdaptersToHeaders(nil))
}
